import React from 'react';
import './PostureVisualizer.css';

const PostureVisualizer = ({ data }) => {
  if (!data) {
    return (
      <div className="posture-visualizer">
        <h2>Posture Visualization</h2>
        <div className="loading">Waiting for data...</div>
      </div>
    );
  }

  // 5-FSR configuration: seat front left/right + seat back + backrest upper/lower
  const seatPressure = {
    frontLeft: data.fsr_seat_front_left || 0,
    frontRight: data.fsr_seat_front_right || 0,
    back: data.fsr_seat_back || 0,
    // combined (firmware sends max of L/R)
    frontCombined: data.fsr_seat_front || 0,
  };

  const backrestPressure = {
    upper: data.fsr_back_upper || 0,
    lower: data.fsr_back_lower || 0,
  };

  // Normalize to 0-100 for visualization (ESP32 ADC is 0..4095)
  const normalize = (value) => Math.min(100, (value / 4095) * 100);

  // Determine posture status
  const getPostureStatus = () => {
    const score = data.posture_score || 0;
    if (score >= 80) return { text: 'Good', color: '#4CAF50' };
    if (score >= 60) return { text: 'Fair', color: '#FF9800' };
    return { text: 'Poor', color: '#F44336' };
  };

  const postureStatus = getPostureStatus();

  return (
    <div className="posture-visualizer">
      <h2>Posture Visualization</h2>
      
      <div className="posture-status">
        <div className="status-indicator" style={{ backgroundColor: postureStatus.color }}>
          {postureStatus.text}
        </div>
        <div className="score-display">
          Score: {data.posture_score?.toFixed(1) || 0}
        </div>
      </div>

      <div className="chair-diagram">
        {/* Backrest (Upper / Lower) */}
        <div className="backrest">
          <div className="pressure-grid">
            <div
              className="pressure-cell"
              style={{ opacity: normalize(backrestPressure.upper) / 100 }}
            >
              Upper
            </div>
            <div
              className="pressure-cell"
              style={{ opacity: normalize(backrestPressure.lower) / 100 }}
            >
              Lower
            </div>
          </div>
        </div>

        {/* Seat (Front L / Front R / Back) */}
        <div className="seat">
          <div className="pressure-grid pressure-grid-seat">
            <div
              className="pressure-cell"
              style={{ opacity: normalize(seatPressure.frontLeft) / 100 }}
            >
              Front L
            </div>
            <div
              className="pressure-cell"
              style={{ opacity: normalize(seatPressure.frontRight) / 100 }}
            >
              Front R
            </div>
            <div
              className="pressure-cell"
              style={{ opacity: normalize(seatPressure.back) / 100 }}
            >
              Back
            </div>
          </div>
        </div>
      </div>

      <div className="posture-metrics">
        <div className="metric">
          <label>Pitch:</label>
          <span>{data.pitch?.toFixed(1) || 0}°</span>
        </div>
        <div className="metric">
          <label>Roll:</label>
          <span>{data.roll?.toFixed(1) || 0}°</span>
        </div>
      </div>
    </div>
  );
};

export default PostureVisualizer;
